import{_ as t,o as s,c as a,ag as r}from"./chunks/framework.ePeAWSvT.js";const i="/assets/datahub-endpoint-settings-tab.aV6D2FTM.png",n="/assets/endpoint-settings-override-key-source-publisher.DwNXHKD0.png",o="/assets/endpoint-settings-override-key-source-model-property.DdcpnzZa.png",y=JSON.parse('{"title":"Endpoint Settings","description":"","frontmatter":{},"headers":[],"relativePath":"guide/datahub-endpoint-settings.md","filePath":"guide/datahub-endpoint-settings.md"}'),l={name:"guide/datahub-endpoint-settings.md"};function h(p,e,d,c,u,g){return s(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="endpoint-settings" tabindex="-1">Endpoint Settings <a class="header-anchor" href="#endpoint-settings" aria-label="Permalink to &quot;Endpoint Settings&quot;">​</a></h1><p>Each endpoint has a <strong>Settings</strong> tab where you can configure processing behavior. The available settings depend on whether the endpoint is a publisher, subscriber, or both.</p><p><img src="'+i+'" alt="Endpoint Settings Tab"></p><h2 id="post-receipt-replication-messages" tabindex="-1">Post Receipt Replication Messages <a class="header-anchor" href="#post-receipt-replication-messages" aria-label="Permalink to &quot;Post Receipt Replication Messages&quot;">​</a></h2><p><em>Subscriber only</em></p><p>When enabled, delivery receipts produced by this subscriber are published to a replication topic. A publishing endpoint with a configured <strong>Receipt Save Action</strong> can then pick up these receipts and write them back to the source system (e.g. as a system log entry). This is useful for confirming delivery status back to the originating connector.</p><p>Receipts can be filtered at the publishing endpoint by <strong>Receipt Level</strong> — all receipts, just errors, or just successful ones.</p><h2 id="override-key-source" tabindex="-1">Override Key Source <a class="header-anchor" href="#override-key-source" aria-label="Permalink to &quot;Override Key Source&quot;">​</a></h2><p><em>Subscriber only</em></p><p><img src="'+n+'" alt="Override Key Source — Publisher Key"></p><p>By default, a subscriber&#39;s primary key is derived from the engine&#39;s standard key resolution — typically an <strong>ObtainPrimaryKey</strong> action in the endpoint&#39;s save flow, or from previously accumulated keys on the indexed entity. The <strong>Override Key Source</strong> toggle lets you bypass that default and explicitly choose where the subscriber&#39;s primary key comes from.</p><p>When the toggle is <strong>off</strong> (default), key resolution follows the standard engine path. When toggled <strong>on</strong>, a <strong>Primary Key Source</strong> dropdown appears with two options:</p><h3 id="use-publisher-key" tabindex="-1">Use Publisher Key <a class="header-anchor" href="#use-publisher-key" aria-label="Permalink to &quot;Use Publisher Key&quot;">​</a></h3><p>The subscriber uses the <strong>inbound message&#39;s publisher key</strong> (the source system&#39;s primary key) as its own primary key. This is useful when the subscriber system should store the same identifier that the publisher uses, eliminating the need for a separate key assignment step.</p><h3 id="use-model-property" tabindex="-1">Use Model Property <a class="header-anchor" href="#use-model-property" aria-label="Permalink to &quot;Use Model Property&quot;">​</a></h3><p><img src="'+o+'" alt="Override Key Source — Model Property"></p><p>The subscriber derives its primary key from a <strong>property on the entity model</strong>. When selected, a property picker appears showing all simple (non-foreign-key) properties from the endpoint&#39;s schema. Select the property whose value should become the subscriber&#39;s primary key.</p><p>This supports both standard properties (via <code>BusProperty</code>) and custom data fields (via <code>CommonName</code>). The selected property map can also include transforms, so you can derive the key from a computed value.</p><div class="tip custom-block"><p class="custom-block-title">When to use Override Key Source</p><p>Common scenarios:</p><ul><li><strong>Publisher Key</strong>: When the subscriber should reuse the source system&#39;s ID (e.g. syncing a record back to a shared reference system)</li><li><strong>Model Property</strong>: When the subscriber&#39;s key comes from a business field like an order number, SKU, or external reference ID that exists on the entity model</li></ul></div><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Override Key Source cannot be used alongside an <strong>ObtainPrimaryKey</strong> action targeting the same key (<code>Id</code>). If both are configured, a validation error will be raised on save.</p></div><h2 id="enable-property-change-tracking" tabindex="-1">Enable Property Change Tracking <a class="header-anchor" href="#enable-property-change-tracking" aria-label="Permalink to &quot;Enable Property Change Tracking&quot;">​</a></h2><p><em>Publisher only</em></p><p>When enabled, the publisher compares each new message against the most recently published message for the same entity. If none of the mapped properties have changed, the message is filtered out and not published. This prevents redundant downstream processing when an entity is re-read but its relevant data hasn&#39;t actually changed.</p><p>The comparison uses the endpoint&#39;s Read property maps to determine which fields to check. Only <code>Save</code> events are evaluated — <code>Delete</code> events are always published.</p><h2 id="parallel-process-count" tabindex="-1">Parallel Process Count <a class="header-anchor" href="#parallel-process-count" aria-label="Permalink to &quot;Parallel Process Count&quot;">​</a></h2><p><em>Publisher and Subscriber</em></p><p>Controls the degree of parallelism when the endpoint processes messages. The engine uses this value as the <code>MaxDegreeOfParallelism</code> for message publishing and receipt processing operations.</p><ul><li>Defaults to <strong>1</strong> (sequential processing) when unset or <code>0</code></li><li>Increase the count to process multiple messages concurrently, improving throughput for high-volume integrations</li><li>Each parallel operation includes automatic retry logic (up to 10 retries)</li><li>Higher values consume more system resources — increase gradually and monitor performance</li></ul><h2 id="concurrency-limit" tabindex="-1">Concurrency Limit <a class="header-anchor" href="#concurrency-limit" aria-label="Permalink to &quot;Concurrency Limit&quot;">​</a></h2><p><em>Subscriber only</em></p><p>Controls how many messages the Azure Service Bus processor can handle concurrently for this subscriber. Unlike Parallel Process Count (which controls parallelism within a processing batch), this setting governs how many messages the bus delivers to the subscriber at the same time.</p><p>Must be at least <strong>1</strong> if set. When left unset, the Service Bus default applies.</p><h2 id="supported-operations" tabindex="-1">Supported Operations <a class="header-anchor" href="#supported-operations" aria-label="Permalink to &quot;Supported Operations&quot;">​</a></h2><p><em>Publisher and Subscriber</em></p><p>Defines which CRUD operations (Create, Read, Update, Delete) the endpoint supports. This controls which messages the endpoint will process or publish.</p><ul><li>When <strong>no operations are selected</strong>, the endpoint supports Create, Read, and Update by default</li><li><strong>Delete must be explicitly enabled</strong> — it is never implicitly supported, even when the list is empty. This is a safety mechanism to prevent accidental deletions</li><li>For subscribers, the engine determines whether an incoming message is a Create or Update by checking if the entity already has a primary key for the subscriber&#39;s system</li></ul><p>The same operation filtering is also applied at the map group and individual property map levels, allowing fine-grained control over which fields participate in each operation.</p><h2 id="supported-systems" tabindex="-1">Supported Systems <a class="header-anchor" href="#supported-systems" aria-label="Permalink to &quot;Supported Systems&quot;">​</a></h2><p><em>When configured</em></p><p>Restricts the endpoint to only process messages from specific source systems. When the list is empty, all systems are accepted. Use this to limit which connected systems can publish to or subscribe from this endpoint.</p><h2 id="engine-behavior" tabindex="-1">Engine Behavior <a class="header-anchor" href="#engine-behavior" aria-label="Permalink to &quot;Engine Behavior&quot;">​</a></h2><p>Engine behavior settings control how the processing engine handles messages at a lower level. Publisher and subscriber settings are configured separately.</p><h3 id="subscriber-settings" tabindex="-1">Subscriber Settings <a class="header-anchor" href="#subscriber-settings" aria-label="Permalink to &quot;Subscriber Settings&quot;">​</a></h3><h4 id="ignore-same-system-constraint" tabindex="-1">Ignore Same System Constraint <a class="header-anchor" href="#ignore-same-system-constraint" aria-label="Permalink to &quot;Ignore Same System Constraint&quot;">​</a></h4><p>By default, a subscriber will <strong>not</strong> process messages that originated from its own system. This prevents circular sync loops where a system receives its own changes back.</p><p>Enabling this setting bypasses that check, allowing the subscriber to process messages from its own system. Use this when you intentionally need a system to react to its own published changes.</p><h3 id="publisher-settings" tabindex="-1">Publisher Settings <a class="header-anchor" href="#publisher-settings" aria-label="Permalink to &quot;Publisher Settings&quot;">​</a></h3><h4 id="header-only" tabindex="-1">Header Only <a class="header-anchor" href="#header-only" aria-label="Permalink to &quot;Header Only&quot;">​</a></h4><p>When enabled, the publisher only processes the header (parent) entity data. Child entity lists are not loaded from the database or merged from the integration message.</p><p>Use this when you only need to sync top-level entity fields and want to skip the overhead of processing child collections (e.g. line items, resources).</p><h4 id="skip-index" tabindex="-1">Skip Index <a class="header-anchor" href="#skip-index" aria-label="Permalink to &quot;Skip Index&quot;">​</a></h4><p>When enabled, the entity is <strong>not saved</strong> to the index after processing. The message is still published to subscribers, but no record is persisted locally.</p><p>This is useful for pass-through scenarios where you want to relay data downstream without maintaining a local copy.</p><h4 id="index-only" tabindex="-1">Index Only <a class="header-anchor" href="#index-only" aria-label="Permalink to &quot;Index Only&quot;">​</a></h4><p>When enabled, the entity is saved to the local index but is <strong>not published</strong> to the subscriber topic. No downstream subscribers will receive the message.</p><p>Use this to build up the local entity index (e.g. during an initial data load) without triggering subscriber processing. Key accumulation is also skipped unless Send to Search is enabled.</p><h4 id="lookup-using-all-primary-keys" tabindex="-1">Lookup Using All Primary Keys <a class="header-anchor" href="#lookup-using-all-primary-keys" aria-label="Permalink to &quot;Lookup Using All Primary Keys&quot;">​</a></h4><p>When the engine cannot find an existing entity using the standard primary key, enabling this setting tells it to attempt a lookup using any <strong>other</strong> primary keys present in the message. This is a fallback mechanism — if the standard key doesn&#39;t match, the engine searches by alternate keys before deciding to create a new entity.</p><p>If multiple entities match the alternate keys, an error is thrown to prevent ambiguous updates.</p><h4 id="allow-multiple-primary-keys" tabindex="-1">Allow Multiple Primary Keys <a class="header-anchor" href="#allow-multiple-primary-keys" aria-label="Permalink to &quot;Allow Multiple Primary Keys&quot;">​</a></h4><p>This setting appears when <strong>Lookup Using All Primary Keys</strong> is enabled. It is configured <strong>per system</strong> — you toggle it on for each source system that should be allowed to store multiple primary keys on the same entity.</p><p>By default, each source system can only have one primary key per entity. If a new key arrives with a different ID for the same system, the engine either updates the existing key (if the key allows changes) or throws an error. When this setting is enabled for a system, additional keys with different IDs are added alongside existing ones instead of replacing them.</p><h2 id="see-also" tabindex="-1">See Also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See Also&quot;">​</a></h2><ul><li><a href="./datahub-scheduling.html">Scheduling &amp; Automation</a> — Configure when publishers run and set up filters</li><li><a href="./datahub-key-scraping.html">Key Scraping</a> — Configure how primary keys are indexed after saves</li><li><a href="./datahub-endpoint-config.html">Endpoint Configuration</a> — Configure endpoint action inputs</li><li><a href="./datahub-action-mapping.html">Action Mapping</a> — Map endpoint actions to Common Model properties</li></ul>',64)])])}const b=t(l,[["render",h]]);export{y as __pageData,b as default};
